// ========== submitWorkspaceJoinRequest ==========

@Override
@Transactional(rollbackFor = Exception.class)
public void submitWorkspaceJoinRequest(String workspaceId, Long applicantUserId) {
    ExceptionUtil.isNotNull(workspaceId, PermissionRequestException.NODE_NOT_EXIST);
    ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);

    // 1. Check no pending workspace request
    PermissionRequestEntity pending = baseMapper.selectPendingWorkspaceBySpaceAndApplicant(workspaceId, applicantUserId);
    ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_WORKSPACE_REQUEST);

    // 2. Get applicant nickname and space name
    String applicantNickName = getApplicantNickName(applicantUserId);
    SpaceEntity space = spaceService.getBySpaceId(workspaceId);
    String spaceName = space != null && space.getName() != null ? space.getName() : workspaceId;

    // 3. Create permission request record
    String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
    PermissionRequestEntity entity = PermissionRequestEntity.builder()
        .id(requestId)
        .type(TYPE_WORKSPACE)
        .applicantUserId(applicantUserId)
        .documentId(workspaceId)
        .documentName(spaceName)
        .spaceId(workspaceId)
        .requestedPermissionType(null)
        .status(STATUS_PENDING)
        .isDeleted(0)
        .createdAt(LocalDateTime.now())
        .updatedAt(LocalDateTime.now())
        .build();

    boolean flag = save(entity);
    if (!flag) {
        log.error("[2423-WorkspaceJoin] ERROR CREATE insert failed applicantUserId={} workspaceId={}",
            applicantUserId, workspaceId);
        throw new BusinessException(PermissionRequestException.INSERT_ERROR);
    }
    log.info("[2423-WorkspaceJoin] CREATE request requestId={} applicantUserId={} workspaceId={}",
        requestId, applicantUserId, workspaceId);

    // 4. Get space admins as notification recipients
    List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(workspaceId);
    if (CollUtil.isEmpty(adminUserIds)) {
        log.warn("[2423-WorkspaceJoin] no admins workspaceId={}", workspaceId);
        return;
    }
    // Exclude applicant from recipients
    adminUserIds = new ArrayList<>(adminUserIds);
    adminUserIds.remove(applicantUserId);
    if (CollUtil.isEmpty(adminUserIds)) {
        log.warn("[2423-WorkspaceJoin] applicant is the only admin workspaceId={}", workspaceId);
        return;
    }

    // 5. Send notification via apitable notification center
    notifyWorkspaceAdminsAsync(entity, spaceName, applicantNickName, adminUserIds);
}

@Async
public void notifyWorkspaceAdminsAsync(PermissionRequestEntity request, String spaceName,
                                        String applicantNickName, List<Long> adminUserIds) {
    try {
        Map<String, Object> extras = new HashMap<>();
        extras.put("requestId", request.getId());
        extras.put("type", TYPE_WORKSPACE);
        extras.put("spaceName", spaceName);
        extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
        extras.put("applicantNickName", applicantNickName);
        extras.put("documentId", request.getDocumentId());
        extras.put("documentName", spaceName);
        extras.put("status", request.getStatus());

        Map<String, Object> bodyMap = new HashMap<>();
        bodyMap.put(BODY_EXTRAS, extras);
        String bodyJson = JSONUtil.toJsonStr(bodyMap);

        apitableGrpcClientService.createNotification(
            DOCUMENT_PERMISSION_REQUEST,
            String.valueOf(request.getApplicantUserId()),
            adminUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
            request.getDocumentId(),
            request.getSpaceId(),
            bodyJson,
            true
        );

        log.info("[2423-WorkspaceJoin] notifyAdmins done requestId={} adminCount={}",
            request.getId(), adminUserIds.size());
    } catch (Exception e) {
        log.error("[2423-WorkspaceJoin] ERROR notifyAdmins requestId={} error={}",
            request.getId(), e.getMessage(), e);
    }
}

